0B,CAAT,CAAC;0CAFhC;wCAIA,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,kBAGL,CAHsB,CAAA;4CAC3B,IAAgD,MAAA,CAAA,CAAA,IAA1C,WAAM,mBAAoC,CAAlB,CAAC,aAA/B,CAAyC;4CACzC,IAAiE,MAAA,CAAA,CAAA,IAA3D,WAAM,kBAAqD,CAApC,CAAC;;sCAPlC;oCAUA,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,gBAEL,CAFoB,CAAA;wCACzB,IAAwC,MAAA,CAAA,CAAA,IAAlC,WAAM;sCADd;oCAGA,IAaO,MAAA,CAAA,CAAA,IAbD,WAAM,aAaL,CAbiB,CAAA;wCACtB,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,YAGL,CAHgB,CAAA;4CACrB,IAAoC,MAAA,CAAA,CAAA,IAA9B,WAAM,gBAAwB,CAAT,CAAC,IAA5B,CAA6B;4CAC7B,IAAwC,MAAA,CAAA,CAAA,IAAlC,WAAM,iBAA4B,CAAZ,CAAC;0CAF/B;wCAIA,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,YAGL,CAHgB,CAAA;4CACrB,IAAoC,MAAA,CAAA,CAAA,IAA9B,WAAM,gBAAwB,CAAT,CAAC,IAA5B,CAA6B;4CAC7B,IAAyC,MAAA,CAAA,CAAA,IAAnC,WAAM,iBAA6B,CAAb,CAAC;0CAF/B;wCAIA,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,YAGL,CAHgB,CAAA;4CACrB,IAAoC,MAAA,CAAA,CAAA,IAA9B,WAAM,gBAAwB,CAAT,CAAC,IAA5B,CAA6B;4CAC7B,IAA2C,MAAA,CAAA,CAAA,IAArC,WAAM,iBAA+B,CAAf,CAAC;;sCAXjC;oCAcA,IAA4D,MAAA,CAAA,CAAA,IAAtD,WAAM,cAAgD,CAAnC,CAAC;;;;;0BA3C9B;wBA+CA,IAOO,MAAA,CAAA,CAAA,IAPD,WAAM,YAOL,CAPgB,CAAA;4BACrB,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,mBAAmB,aAAK,SAE7B;gCADL,IAAiD,MAAA,CAAA,CAAA,IAA3C,WAAM,uBAAqC,CAAf,CAAC;8BADrC;4BAGA,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,qBAAqB,aAAK,UAE/B;gCADL,IAA+C,MAAA,CAAA,CAAA,IAAzC,WAAM,yBAAmC,CAAX,CAAC;;0BALzC;wBASA,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,eAEL,CAFmB,CAAA;4BACxB,IAAqD,MAAA,CAAA,CAAA,IAA/C,WAAM,cAAyC,CAA5B,CAAC"}
=======
{"version":3,"sources":["pages/guide/index.uvue","App.uvue"],"sourcesContent":["<template>\n  <view class=\"page\">\n    <view class=\"page-bg\">\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\n    </view>\n    <view class=\"bg-glow glow-purple\"></view>\n    <view class=\"bg-glow glow-blue\"></view>\n    <view class=\"bg-glow glow-pink\"></view>\n    <view class=\"sky-star star-a\"></view>\n    <view class=\"sky-star star-b\"></view>\n    <view class=\"sky-star star-c\"></view>\n    <view class=\"sky-star star-d\"></view>\n    <view class=\"sky-star star-e\"></view>\n    <view class=\"sky-star star-f\"></view>\n    <view class=\"sky-star star-g\"></view>\n    <view class=\"sky-star star-h\"></view>\n    <view class=\"sky-star star-i\"></view>\n    <view class=\"sky-star star-j\"></view>\n    <view class=\"sky-star star-k\"></view>\n    <view class=\"sky-star star-l\"></view>\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\n      <view class=\"hero-block\">\n        <view class=\"hero-copy\">\n          <text class=\"hero-brand\">微憩星球</text>\n          <text class=\"hero-title\">轻轻守护，从 10 秒开始</text>\n          <text class=\"hero-subtitle\">它会观察你的使用节奏，在合适的时候提醒你眨眨眼、松松肩、慢慢呼吸。</text>\n        </view>\n        <view class=\"hero-planet-card\">\n          <image class=\"hero-mascot-img\" src=\"/static/images/micro-planet-mascot.png\" mode=\"aspectFit\"></image>\n          <text class=\"hero-chip\">不说教 · 不打扰</text>\n        </view>\n      </view>\n\n      <view class=\"value-block\">\n        <text class=\"block-title\">AI 健康大脑在做什么</text>\n        <text class=\"block-subtitle\">不是催你打卡，而是把使用节奏、完成反馈和健康状态一起看懂。</text>\n        <view class=\"ai-core-card\">\n          <view class=\"ai-core-icon\">\n            <text class=\"ai-core-icon-text\">AI</text>\n          </view>\n          <view class=\"ai-core-copy\">\n            <text class=\"ai-core-title\">先判断，再轻轻提醒</text>\n            <text class=\"ai-core-text\">本地规则引擎实时看连续使用时长，推荐算法选择当下更适合的护眼、体态或呼吸动作。</text>\n          </view>\n        </view>\n        <view class=\"value-grid\">\n          <view class=\"value-card\">\n            <text class=\"value-icon value-icon-blue\">◌</text>\n            <text class=\"value-title\">解决忘休息</text>\n            <text class=\"value-text\">刷久了才提醒，不靠你自己想起来</text>\n          </view>\n          <view class=\"value-card value-card-even\">\n            <text class=\"value-icon value-icon-purple\">✦</text>\n            <text class=\"value-title\">推荐做什么</text>\n            <text class=\"value-text\">按时间段和历史完成情况选微动作</text>\n          </view>\n          <view class=\"value-card\">\n            <text class=\"value-icon value-icon-pink\">⌁</text>\n            <text class=\"value-title\">AI 小结报告</text>\n            <text class=\"value-text\">每日一句话、每周建议和下周小目标</text>\n          </view>\n          <view class=\"value-card value-card-even\">\n            <text class=\"value-icon value-icon-blue\">◐</text>\n            <text class=\"value-title\">越用越懂你</text>\n            <text class=\"value-text\">完成、跳过、忙一下，都会帮助调节频率</text>\n          </view>\n        </view>\n        <text class=\"value-privacy\">只识别你正在使用哪个 App 和连续用了多久，不读取聊天内容、密码或屏幕文字。</text>\n      </view>\n\n      <view class=\"focus-block\">\n        <text class=\"block-title\">选择守护重点</text>\n        <text class=\"block-subtitle\">之后可以随时修改，现在先选一个你最想照顾的方向。</text>\n        <view class=\"focus-grid\">\n          <view class=\"focus-card\" :class=\"selectedFocus === 'eye' ? 'focus-active' : ''\" @tap=\"selectFocus('eye')\">\n            <text class=\"focus-icon\">◐</text>\n            <text class=\"focus-title\">护眼优先</text>\n          </view>\n          <view class=\"focus-card\" :class=\"selectedFocus === 'posture' ? 'focus-active' : ''\" @tap=\"selectFocus('posture')\">\n            <text class=\"focus-icon\">◌</text>\n            <text class=\"focus-title\">肩颈优先</text>\n          </view>\n          <view class=\"focus-card\" :class=\"selectedFocus === 'breath' ? 'focus-active' : ''\" @tap=\"selectFocus('breath')\">\n            <text class=\"focus-icon\">⌁</text>\n            <text class=\"focus-title\">减压呼吸</text>\n          </view>\n          <view class=\"focus-card\" :class=\"selectedFocus === 'balance' ? 'focus-active' : ''\" @tap=\"selectFocus('balance')\">\n            <text class=\"focus-icon\">✧</text>\n            <text class=\"focus-title\">均衡发展</text>\n          </view>\n        </view>\n      </view>\n\n      <view class=\"steps-block\">\n        <text class=\"block-title\">开启轻轻守护</text>\n        <text class=\"block-subtitle\">权限只用于识别 App 和连续使用时长，不读取聊天内容、密码或屏幕文字。</text>\n        <view class=\"step-card\">\n          <view class=\"step-num-wrap step-num-1\">\n            <text class=\"step-num\">1</text>\n          </view>\n          <view class=\"step-content\">\n            <text class=\"step-title\">开启使用情况权限</text>\n            <text class=\"step-desc\">用来检测你正在使用哪个 App，以及连续使用了多久</text>\n            <view class=\"step-status-row\">\n              <text class=\"step-status\" :class=\"usageEnabled ? 'step-status-on' : 'step-status-off'\">\n                {{ usageEnabled ? '✅ 已开启' : '⚪ 未开启' }}\n              </text>\n              <view v-if=\"!usageEnabled\" class=\"step-action-btn\" @tap=\"openUsageAccess\">\n                <text class=\"step-action-btn-text\">立即开启</text>\n              </view>\n            </view>\n          </view>\n        </view>\n\n        <view class=\"step-card\">\n          <view class=\"step-num-wrap step-num-2\">\n            <text class=\"step-num\">2</text>\n          </view>\n          <view class=\"step-content\">\n            <text class=\"step-title\">开启悬浮窗权限</text>\n            <text class=\"step-desc\">用来在其他 App 上方显示微动作提醒</text>\n            <view class=\"step-status-row\">\n              <text class=\"step-status\" :class=\"overlayEnabled ? 'step-status-on' : 'step-status-off'\">\n                {{ overlayEnabled ? '✅ 已开启' : '⚪ 未开启' }}\n              </text>\n              <view v-if=\"!overlayEnabled\" class=\"step-action-btn\" @tap=\"openOverlay\">\n                <text class=\"step-action-btn-text\">立即开启</text>\n              </view>\n            </view>\n          </view>\n        </view>\n\n        <view class=\"step-card step-card-info\">\n          <view class=\"step-num-wrap step-num-3\">\n            <text class=\"step-num\">3</text>\n          </view>\n          <view class=\"step-content\">\n            <text class=\"step-title\">后台守护</text>\n            <text class=\"step-desc\">用来保持提醒服务稳定运行，不打扰你的正常使用</text>\n          </view>\n        </view>\n      </view>\n\n      <view class=\"demo-block\">\n        <text class=\"block-title\">演示一次</text>\n        <text class=\"block-subtitle\">假设你刷屏久了一点，小星球会这样提醒你。</text>\n        <view class=\"demo-card\">\n          <view class=\"demo-planet\">\n            <text class=\"demo-planet-text\">◐</text>\n          </view>\n          <view class=\"demo-copy\">\n            <text class=\"demo-title\">星球信号提醒</text>\n            <text class=\"demo-text\">检测到眼睛电量有点低，要不要眨眼 10 秒？</text>\n          </view>\n          <view class=\"demo-action\" @tap=\"startDemo\">\n            <text class=\"demo-action-text\">{{ demoStarted ? '演示中' : '好啊' }}</text>\n          </view>\n        </view>\n        <view v-if=\"demoStarted\" class=\"demo-flow\">\n          <view class=\"demo-stage\">\n            <view class=\"demo-stage-planet\">\n              <view class=\"demo-stage-orbit\"></view>\n              <text class=\"demo-stage-icon\">◐</text>\n            </view>\n            <view class=\"demo-stage-copy\">\n              <text class=\"demo-stage-title\">进入 10 秒微动作</text>\n              <text class=\"demo-stage-text\">真实使用时会进入动作页，显示引导文案、倒计时和跳过按钮。</text>\n            </view>\n          </view>\n          <view class=\"demo-progress\">\n            <view class=\"demo-progress-fill\"></view>\n          </view>\n          <view class=\"demo-steps\">\n            <view class=\"demo-step\">\n              <text class=\"demo-step-num\">1</text>\n              <text class=\"demo-step-text\">收到提醒</text>\n            </view>\n            <view class=\"demo-step\">\n              <text class=\"demo-step-num\">2</text>\n              <text class=\"demo-step-text\">点“好啊”</text>\n            </view>\n            <view class=\"demo-step\">\n              <text class=\"demo-step-num\">3</text>\n              <text class=\"demo-step-text\">跟着倒计时做完</text>\n            </view>\n          </view>\n          <text class=\"demo-result\">完成后，小星球会点亮一次，并把这次照顾记录进健康轨迹。</text>\n        </view>\n      </view>\n\n      <view class=\"cta-block\">\n        <view class=\"cta-btn-primary\" @tap=\"startApp\">\n          <text class=\"cta-btn-primary-text\">开始我的小星球</text>\n        </view>\n        <view class=\"cta-btn-secondary\" @tap=\"skipGuide\">\n          <text class=\"cta-btn-secondary-text\">先逛逛</text>\n        </view>\n      </view>\n\n      <view class=\"footer-block\">\n        <text class=\"footer-text\">v1.0.0 · 守护你的每一次温柔停顿</text>\n      </view>\n    </scroll-view>\n  </view>\n</template>\n\n<script setup lang=\"uts\">\nimport { putInt } from '../../database/SettingsDao'\nimport { isUsagePermissionGranted, openUsageAccessSettings } from '../../uni_modules/uts-usage-stats/utssdk/app-android/index'\nimport { hasOverlayPermission, requestOverlayPermission } from '../../uni_modules/uts-floating-overlay/utssdk/app-android/index'\n\nconst usageEnabled = ref<boolean>(isUsagePermissionGranted())\nconst overlayEnabled = ref<boolean>(hasOverlayPermission())\nconst selectedFocus = ref<string>('balance')\nconst demoStarted = ref<boolean>(false)\n\nfunction selectFocus(v: string): void {\n  selectedFocus.value = v\n}\n\nfunction startDemo(): void {\n  demoStarted.value = true\n}\n\nfunction refreshPermissionStates(): void {\n  usageEnabled.value = isUsagePermissionGranted()\n  overlayEnabled.value = hasOverlayPermission()\n}\n\nfunction openUsageAccess(): void {\n  openUsageAcc